def _load_embedded_namespace(source_text: str, module_name: str):
    ns = {"__name__": module_name}
    exec(source_text, ns)
    return ns


WINNER = _load_embedded_namespace(WINNER_SOURCE, "embedded_core025_winner")
SKIP = _load_embedded_namespace(SKIP_SOURCE, "embedded_core025_skip")


def _uploaded_to_df(uploaded_file) -> pd.DataFrame:
    if uploaded_file is None:
        raise ValueError("Missing uploaded file.")
    return WINNER["load_table"](uploaded_file)


def _trim_raw_history(df: pd.DataFrame, max_rows: int) -> pd.DataFrame:
    if max_rows and len(df) > int(max_rows):
        return df.tail(int(max_rows)).reset_index(drop=True)
    return df.copy().reset_index(drop=True)


def _winner_survivors_from_raw(raw_df: pd.DataFrame) -> pd.DataFrame:
    hist = WINNER["prep_history"](raw_df)
    latest = hist.sort_values(["stream", "date"]).groupby("stream", as_index=False).tail(1).copy()
    surv = latest[["stream", "r4"]].rename(columns={"r4": "seed"}).reset_index(drop=True)
    return WINNER["prep_survivors"](surv)


def _winner_download_name(base: str) -> str:
    return f"{base}__2026-04-05_v6_exact_source_self_contained.csv"


def _skip_download_name(base: str, ext: str = "csv") -> str:
    return f"{base}__2026-04-05_v6_exact_source_self_contained.{ext}"


def _download_df(label: str, df: pd.DataFrame, file_name: str):
    st.download_button(label, data=df.to_csv(index=False), file_name=file_name, mime="text/csv")


def _render_winner_lab_exact(results: Dict[str, pd.DataFrame], rows_to_show: int):
    per_event = results["per_event"]
    per_date = results["per_date"]
    per_stream = results["per_stream"]
    by_mode = results["by_mode"]
    summary = results["summary"]

    WINNER["render_lab_results"](per_event, per_date, per_stream, by_mode, summary, rows_to_show)
    # Additional explicit by-mode download to keep each output individually downloadable.
    _download_df(
        "Download winner by-mode CSV",
        by_mode,
        _winner_download_name("core025_lab_by_mode"),
    )


def _render_skip_lab_exact(results: Dict[str, object], rows_to_show: int):
    transitions_df = results["transitions"]
    st.success(f"Completed at UTC: {results['completed_at_utc']}")

    c1, c2, c3, c4 = st.columns(4)
    c1.metric("Transition events", f"{len(transitions_df):,}")
    c2.metric("Core025 hits", f"{int(transitions_df['next_is_core025_hit'].sum()):,}")
    c3.metric("Base rate", f"{float(transitions_df['next_is_core025_hit'].mean()):.4f}")
    c4.metric("Chosen cutoff", f"{float(results['recommended_cutoff'].iloc[0]['max_skip_score_included']) if len(results['recommended_cutoff']) else 1.0:.6f}")

    st.subheader("Summary")
    st.text_area("Summary text", results["summary_text"], height=380)
    st.download_button(
        "Download skip summary TXT",
        data=results["summary_text"].encode("utf-8"),
        file_name=_skip_download_name("core025_skip_ladder_summary", "txt"),
        mime="text/plain",
    )

    st.markdown("## Recommended cutoff")
    st.dataframe(results["recommended_cutoff"], use_container_width=True)
    _download_df("Download skip recommended cutoff CSV", results["recommended_cutoff"], _skip_download_name("core025_skip_ladder_recommended_cutoff"))

    st.markdown("## Retention ladder")
    st.dataframe(SKIP["safe_display_df"](results["retention_ladder"], int(rows_to_show)), use_container_width=True)
    _download_df("Download skip retention ladder CSV", results["retention_ladder"], _skip_download_name("core025_skip_ladder_retention_ladder"))

    st.markdown("## Scored historical events")
    st.dataframe(SKIP["safe_display_df"](results["scored_events"], int(rows_to_show)), use_container_width=True)
    _download_df("Download skip scored events CSV", results["scored_events"], _skip_download_name("core025_skip_ladder_scored_events"))

    st.markdown("## Current scored streams")
    st.dataframe(SKIP["safe_display_df"](results["current_scored_streams"], int(rows_to_show)), use_container_width=True)
    _download_df("Download skip current scored streams CSV", results["current_scored_streams"], _skip_download_name("core025_skip_ladder_current_scored_streams"))


def _build_comparison(winner_results: Optional[Dict[str, pd.DataFrame]], skip_results: Optional[Dict[str, object]]):
    if not winner_results or not skip_results:
        return None, None
    per_event = winner_results["per_event"].copy()
    scored = skip_results["scored_events"].copy()
    if per_event.empty or scored.empty:
        metrics = pd.DataFrame([
            {"metric": "winner_events", "value": len(per_event)},
            {"metric": "skip_scored_events", "value": len(scored)},
            {"metric": "overlap_rows", "value": 0},
        ])
        return metrics, pd.DataFrame()

    per_event["transition_date"] = pd.to_datetime(per_event["transition_date"], errors="coerce")
    scored["event_date"] = pd.to_datetime(scored["event_date"], errors="coerce")
    merged = per_event.merge(
        scored,
        left_on=["stream", "seed", "transition_date"],
        right_on=["stream_id", "seed", "event_date"],
        how="inner",
        suffixes=("_winner", "_skip"),
    )
    if not merged.empty:
        merged["winner_survived_skip"] = ((merged["top1_hit"].astype(int) == 1) & (merged["skip_class"] == "PLAY")).astype(int)
        merged["winner_stripped_by_skip"] = ((merged["top1_hit"].astype(int) == 1) & (merged["skip_class"] == "SKIP")).astype(int)
    else:
        merged["winner_survived_skip"] = []
        merged["winner_stripped_by_skip"] = []
    metrics = pd.DataFrame([
        {"metric": "winner_events", "value": len(per_event)},
        {"metric": "skip_scored_events", "value": len(scored)},
        {"metric": "overlap_rows", "value": len(merged)},
        {"metric": "winner_top1_hits", "value": int(per_event["top1_hit"].sum()) if "top1_hit" in per_event.columns else 0},
        {"metric": "winner_top2_hits", "value": int(per_event["top2_hit"].sum()) if "top2_hit" in per_event.columns else 0},
        {"metric": "winners_stripped_by_skip", "value": int(merged["winner_stripped_by_skip"].sum()) if not merged.empty else 0},
    ])
    return metrics, merged


def _render_daily_exact(winner_daily: Optional[pd.DataFrame], skip_daily: Optional[pd.DataFrame], rows_to_show: int):
    if winner_daily is None or skip_daily is None:
        st.info("Run Daily KEEP / STRIP to generate the merged board.")
        return
    merged = winner_daily.merge(skip_daily, left_on=["stream", "seed"], right_on=["stream_id", "seed"], how="left")
    merged["skip_class"] = merged["skip_class"].fillna("PLAY")
    merged["action"] = merged["skip_class"].map(lambda x: "KEEP" if x == "PLAY" else "STRIP")

    keep_df = merged[merged["action"] == "KEEP"].reset_index(drop=True)
    strip_df = merged[merged["action"] == "STRIP"].reset_index(drop=True)

    c1, c2, c3 = st.columns(3)
    c1.metric("Merged rows", f"{len(merged):,}")
    c2.metric("KEEP", f"{len(keep_df):,}")
    c3.metric("STRIP", f"{len(strip_df):,}")

    st.subheader("KEEP list")
    st.dataframe(keep_df.head(int(rows_to_show)), use_container_width=True)
    _download_df("Download daily KEEP CSV", keep_df, _skip_download_name("core025_daily_keep_list"))

    st.subheader("STRIP list")
    st.dataframe(strip_df.head(int(rows_to_show)), use_container_width=True)
    _download_df("Download daily STRIP CSV", strip_df, _skip_download_name("core025_daily_strip_list"))

    st.subheader("Merged board")
    st.dataframe(merged.head(int(rows_to_show)), use_container_width=True)
    _download_df("Download daily merged board CSV", merged, _skip_download_name("core025_daily_merged_board"))


